messages.content:
CLUSTER:
[
 {
  "riskId": "risk.boundary-substitution.nl-selfbuild-hollows-second-geography",
  "title": "The best-triangulated geography is the trap: NL's 28% sits on a capped colo base while its growth migrates to self-build architectures a regional entrant can't quote into",
  "narrative": "geo.NL is the model's most reassuring node — Statista and the Dutch Data Center Association agree within 3%. But that triangulation validates yesterday's colocation stock, not the composition of forward demand. The Netherlands is one of four countries holding ~60% of Europe's hyperscale self-build capacity, and self-build is growing 24% YoY versus colo's 19% — while Amsterdam (≈70% of NL colo) is supply-constrained. So the venture's second-largest geography weight (28% of the base) rests on a slice where the PDU-native part is capped and the growing part procures through hyperscaler global frameworks and busway/shelf architectures that a pre-launch regional entrant cannot reach in its first 12 months. The MW totals will keep rising; the biddable NL demand won't.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "NL is among the four countries concentrating ~60% of Europe's operational hyperscale self-build capacity, and European self-build additions grow 24% YoY — in NL, forward capacity growth increasingly happens outside the 951MW colo base that geo.NL's 0.28 apportionment measures",
    "refs": [
     "digest:seg-mix#c14",
     "digest:seg-mix#c12",
     "ledger:geo.NL"
    ]
   },
   {
    "step": "propagation",
    "text": "Self-build capacity procures power distribution through hyperscaler global specs rather than regional channels, while the colo segment — larger but slower at 19% YoY and slowly losing share of total capacity — is the only NL demand a new CE entrant can actually bid; Amsterdam supply constraints cap even that",
    "refs": [
     "digest:seg-mix#c13",
     "digest:seg-mix#c18"
    ]
   },
   {
    "step": "model-impact",
    "text": "geo.NL 0.28 overstates the entrant-reachable Dutch slice during the pre-launch first-12-months window: the ratio is anchored to a stalling colo stock while the growth it implicitly promises accrues to out-of-category, out-of-channel self-build",
    "refs": [
     "ledger:geo.NL",
     "profile:Stage"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "NL colocation capacity growth vs hyperscale self-build additions",
    "where": "Dutch Data Center Association 'State of the Dutch Data Centers' annual report; CBRE Amsterdam market quarterlies",
    "threshold": "NL colo net additions <5% YoY while national self-build MW grows >20%",
    "updates": "increases"
   },
   {
    "signal": "Grid-connection allocations for new NL data-center projects",
    "where": "Liander/TenneT congestion and connection-queue publications for the Amsterdam metro and Middenmeer/Eemshaven zones",
    "threshold": "New allocations flowing predominantly to hyperscale campus projects rather than colo expansions",
    "updates": "increases"
   }
  ],
  "judgeTotal": 17
 },
 {
  "riskId": "risk.ledger-self-audit.nl-frozen-colo-stock-share-decay",
  "title": "NL's 0.28 is a share of a stock that regulation has frozen — growth migrates to self-build hyperscale the entrant reaches through a different (foreclosed) door",
  "narrative": "geo.NL looks like the model's safest node: Statista and the Dutch Data Center Association agree within 3%. But both measure the same thing — the existing colo stock — and that stock is capped: Amsterdam's 350 MVA ceiling and grid connections unavailable until 2030 freeze the region holding ~70% of Dutch colo capacity, while NL hyperscale self-build grows at a forecast ~26% CAGR against colo's ~3.5%. The 0.28 therefore describes where the market was, not where the next five years of PDU purchase orders will originate. Worse, the demand that does grow in NL arrives via hyperscale self-build procurement — exactly the framework-locked channel already flagged as least contestable — so the entrant's effective NL opportunity decays on two axes at once: the reachable segment shrinks and the growing segment is behind a closed door.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "Dutch grid and municipal policy (Amsterdam MVA ceiling, hyperscale siting restrictions, power connection queues to 2030) caps new colo capacity in the region that concentrates ~70% of NL colocation",
    "refs": [
     "ledger:geo.NL",
     "digest:geo-NL#c7",
     "digest:geo-NL#c8"
    ]
   },
   {
    "step": "propagation",
    "text": "NL demand growth shifts to hyperscale self-build (forecast ~26% CAGR vs colo ~3.5%), a segment measured outside the colo-scoped Statista/DDA figures and procured through global frameworks rather than contestable regional purchasing",
    "refs": [
     "digest:geo-NL#c13",
     "digest:geo-region-denominator#c18",
     "ledger:cust.operator-large"
    ]
   },
   {
    "step": "model-impact",
    "text": "geo.NL's 0.28 overstates the entrant's forward-looking NL opportunity: the triangulated agreement between sources validates the frozen stock, not the flow of new PDU demand the Year-1 ramp actually sells into",
    "refs": [
     "ledger:geo.NL",
     "ledger:obtainableFactor"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "Amsterdam-region grid connection grants and the Amsterdam MVA ceiling's status",
    "where": "Liander/TenneT congestion maps and connection-queue publications; Amsterdam municipality data-center policy docket",
    "threshold": "Ceiling extended or queue lengthening beyond 2030",
    "updates": "increases"
   },
   {
    "signal": "Split of NL capacity additions between colocation and hyperscale self-build",
    "where": "Dutch Data Center Association annual 'State of the Dutch Data Centers' report; DC Byte NL market updates",
    "threshold": "Self-build >50% of NL MW additions in the next report vintage",
    "updates": "increases"
   },
   {
    "signal": "PDU refresh/retrofit tender activity from existing Amsterdam-area colos",
    "where": "Operator capex commentary (NorthC, Iron Mountain NL, Equinix AM-campus announcements)",
    "threshold": "Visible retrofit programs at ≥3 AMS operators",
    "updates": "decreases"
   }
  ],
  "judgeTotal": 14
 },
 {
  "riskId": "risk.demand-discontinuity.nl-grid-freeze-share-erosion",
  "title": "The Netherlands' 0.28 slice is legally and electrically frozen for the entire Year-1 window",
  "narrative": "geo.NL = 0.28 is one of the best-triangulated nodes in the ledger — Statista and the DDA agree within 3%. But both measure installed stock, and the venture sells into flow: new fit-outs where a new vendor can be designed in. In NL that flow is administratively shut for the whole first-12-months window: a national decree bans new hyperscale builds outside two municipalities, Amsterdam's draft zoning plan caps connections at 350 MVA until 2030, and distribution firms say no power is available until 2030 — with Amsterdam holding ~70% of national colo. What remains in NL is replacement demand inside operating halls, the most incumbent-locked business there is. Nearly a third of the funnel is a stock share masquerading as an addressable flow.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "National hyperscale ban outside Het Hogeland/Hollands Kroon, Amsterdam's 350 MVA connection ceiling to 2030, and grid operators reporting no power available until 2030",
    "refs": [
     "digest:geo-NL#c7",
     "digest:geo-NL#c8",
     "digest:geo-NL#c9"
    ]
   },
   {
    "step": "propagation",
    "text": "Amsterdam Metro holds ~70% of Dutch colo capacity, so the caps bind the bulk of the country; NL growth already decelerated to 4.9% CAGR 2021–23 — the flow of new fit-outs where a new PDU vendor gets specified approaches zero in the Year-1 window",
    "refs": [
     "digest:geo-NL#c12",
     "digest:geo-NL#c13"
    ]
   },
   {
    "step": "model-impact",
    "text": "NL's share of contestable Year-1 demand is far below its 0.28 installed-capacity share; the geography mix overweights a frozen market and inflates SAM and YAM proportionally",
    "refs": [
     "ledger:geo.NL"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "Adoption status of Amsterdam's umbrella zoning plan and the 350 MVA connection ceiling",
    "where": "Gemeente Amsterdam planning docket and Dutch Data Center Association policy updates",
    "threshold": "Plan adopted with the 350 MVA cap intact",
    "updates": "increases"
   },
   {
    "signal": "National colocation capacity print year-on-year",
    "where": "DDA 'State of the Dutch Data Centers' annual report",
    "threshold": "National colo MW flat at ≤950 MW",
    "updates": "increases"
   }
  ],
  "judgeTotal": 17
 }
]

Every riskId must appear in exactly one group (as keepId or inside absorbs).
Emit JSON: { rationale, groups: [{keepId, absorbs: [true-duplicate riskIds, [] if none], foldedIndicators: []}] }
